#!/usr/bin/env node
// End-to-end parity against the FULL 8-layer / 128-expert model.
// Reads the fixtures generated by `scripts/gen-full-parity-fixture.py`
// (blob + token IDs + reference logits) and runs them through
// `WasmBackend` for comparison.
//
// Usage:
//
//   python3 scripts/gen-full-parity-fixture.py --scratch-dir /tmp/pii-wasm-e2e
//   bun scripts/verify-full-parity.mjs --scratch-dir /tmp/pii-wasm-e2e
//
// Not committed. Not part of CI. Run after any change to the Zig
// kernels, the weight blob format, or the quantization layout.

import { readFile } from "node:fs/promises";
import { parseArgs } from "node:util";
import { join } from "node:path";
import { WasmBackend } from "../src/js/backends/wasm.ts";

function bf16ToF32(u) {
  const buf = new ArrayBuffer(4);
  new DataView(buf).setUint32(0, u << 16, true);
  return new DataView(buf).getFloat32(0, true);
}

async function main() {
  const { values } = parseArgs({
    options: { "scratch-dir": { type: "string" } },
  });
  const scratch = values["scratch-dir"];
  if (!scratch) {
    console.error("--scratch-dir is required (matches gen-full-parity-fixture.py)");
    process.exit(2);
  }

  const blobPath = join(scratch, "pii-weights-full.bin");
  const idsPath = join(scratch, "full_input_ids.i32");
  const refPath = join(scratch, "full_logits.bf16");

  const idsBuf = await readFile(idsPath);
  const ids = new Int32Array(
    idsBuf.buffer.slice(idsBuf.byteOffset, idsBuf.byteOffset + idsBuf.byteLength),
  );
  const refBuf = await readFile(refPath);
  const ref = new Uint16Array(
    refBuf.buffer.slice(refBuf.byteOffset, refBuf.byteOffset + refBuf.byteLength),
  );

  console.log(`[full-parity] T=${ids.length}, loading WasmBackend …`);
  const backend = new WasmBackend({
    weightsUrl: new URL(`file://${blobPath}`),
    bundle: undefined,
    quantization: "int4",
    device: "wasm",
  });
  const t0 = process.hrtime.bigint();
  await backend.warmup();
  const tWarm = Number(process.hrtime.bigint() - t0) / 1e6;
  console.log(`[full-parity] warmup + weight load: ${tWarm.toFixed(1)} ms`);

  const dummyMask = new Uint8Array(ids.length).fill(1);
  const t1 = process.hrtime.bigint();
  const logits = await backend.forward(ids, dummyMask);
  const tForward = Number(process.hrtime.bigint() - t1) / 1e6;
  console.log(`[full-parity] forward: ${tForward.toFixed(1)} ms  (T=${ids.length})`);

  if (logits.data.length !== ref.length) {
    console.error(`shape mismatch: got ${logits.data.length}, expected ${ref.length}`);
    process.exit(1);
  }

  // Diagnostic: per-logit drift statistics. These are informational —
  // large logit drift is allowed as long as the argmax per-token
  // classes match, which is the actual KPI for a token classifier.
  let maxAbs = 0, maxRel = 0, sumSq = 0;
  for (let i = 0; i < ref.length; i++) {
    const g = logits.data[i];
    const w = bf16ToF32(ref[i]);
    const abs = Math.abs(g - w);
    const rel = Math.abs(w) > 0 ? abs / Math.abs(w) : abs;
    if (abs > maxAbs) maxAbs = abs;
    if (rel > maxRel) maxRel = rel;
    sumSq += abs * abs;
  }
  const rms = Math.sqrt(sumSq / ref.length);
  console.log(
    `[full-parity] logit drift  maxAbs=${maxAbs.toExponential(2)}  ` +
    `maxRel=${maxRel.toExponential(2)}  rms=${rms.toExponential(2)}`,
  );

  // Argmax-class agreement — the KPI. If argmax classes match, the
  // downstream Viterbi decoder produces identical spans modulo
  // transition biases (which are the same across backends).
  const T = ids.length, C = 33;
  let classMatches = 0;
  for (let t = 0; t < T; t++) {
    let gBest = 0, gMax = logits.data[t * C];
    let wBest = 0, wMax = bf16ToF32(ref[t * C]);
    for (let c = 1; c < C; c++) {
      if (logits.data[t * C + c] > gMax) { gMax = logits.data[t * C + c]; gBest = c; }
      const w = bf16ToF32(ref[t * C + c]);
      if (w > wMax) { wMax = w; wBest = c; }
    }
    if (gBest === wBest) classMatches++;
  }
  const pass = classMatches === T;
  const tag = pass ? "PASS" : "FAIL";
  console.log(`[full-parity] ${tag}  argmax class agreement: ${classMatches}/${T}`);
  if (!pass) process.exit(1);
  backend.dispose();
}

await main();
